// Apply a .potx template's masters/layouts/theme onto a .pptx generated by pptxgenjs.
// Output: a new .pptx that uses the template's slide master + layouts but keeps every
// shape/text we placed in the source.
//
// Approach: unzip both, replace the source's ppt/theme/, ppt/slideMasters/,
// ppt/slideLayouts/, ppt/fonts/, ppt/notesMasters/, ppt/handoutMasters/ with the
// template's, copy the template's media files referenced by those parts, and
// rewrite Content_Types.xml + ppt/_rels/presentation.xml.rels so OOXML rels resolve.
//
// Each source slide's rels are repointed at the *first* layout of the new template's
// master ("Blank" / "Title" / whatever is layout1) — pptxgenjs uses absolute coords
// so the layout doesn't influence positioning.
//
// Usage:
//   node scripts/apply-pptx-template.mjs <template.potx> <source.pptx> <output.pptx>

import { readFile, writeFile } from "node:fs/promises";
import AdmZip from "adm-zip";

const [, , templatePath, sourcePath, outPath] = process.argv;
if (!templatePath || !sourcePath || !outPath) {
  console.error("Usage: node apply-pptx-template.mjs <template.potx> <source.pptx> <output.pptx>");
  process.exit(2);
}

const tmpl = new AdmZip(await readFile(templatePath));
const src = new AdmZip(await readFile(sourcePath));

// 1. Pick the parts we replace en bloc from the template.
const REPLACE_PREFIXES = [
  "ppt/theme/",
  "ppt/slideMasters/",
  "ppt/slideLayouts/",
  "ppt/fonts/",
  "ppt/notesMasters/",
  "ppt/handoutMasters/",
];

// 2. From the SOURCE, drop everything matching REPLACE_PREFIXES and rebuild it
//    from the template. Keep slides, slide rels, presentation.xml core, etc.
const out = new AdmZip();
for (const entry of src.getEntries()) {
  if (REPLACE_PREFIXES.some((p) => entry.entryName.startsWith(p))) continue;
  out.addFile(entry.entryName, entry.getData());
}

// 3. From the TEMPLATE, copy in the same prefixed parts.
const tmplMediaToCopy = new Set();
for (const entry of tmpl.getEntries()) {
  if (REPLACE_PREFIXES.some((p) => entry.entryName.startsWith(p))) {
    out.addFile(entry.entryName, entry.getData());
    // Scan rels for media references so we can pull them too.
    if (entry.entryName.endsWith(".rels")) {
      const xml = entry.getData().toString("utf8");
      for (const m of xml.matchAll(/Target="\.\.\/media\/([^"]+)"/g)) {
        tmplMediaToCopy.add("ppt/media/" + m[1]);
      }
    }
  }
}

// 4. Add template media (background images, logo, font textures) used by the
//    masters/layouts we just imported. Skip if a same-named file already exists.
const srcMediaNames = new Set(
  src
    .getEntries()
    .filter((e) => e.entryName.startsWith("ppt/media/"))
    .map((e) => e.entryName),
);
for (const name of tmplMediaToCopy) {
  if (srcMediaNames.has(name)) continue;
  const e = tmpl.getEntry(name);
  if (e) out.addFile(name, e.getData());
}

// 5. Rewrite ppt/_rels/presentation.xml.rels — replace the slideMaster/theme/notesMaster/
//    handoutMaster targets with whatever the template provides. Slide targets stay.
const presRelsEntry = out.getEntry("ppt/_rels/presentation.xml.rels");
if (presRelsEntry) {
  let presRels = presRelsEntry.getData().toString("utf8");
  // Drop existing entries pointing into the replaced trees, then append the template's.
  presRels = presRels.replace(
    /<Relationship[^/]*Target="(slideMasters|theme|notesMasters|handoutMasters)\/[^"]+"[^/]*\/>/g,
    "",
  );
  // Pull the template's presentation.xml.rels and lift just those entries.
  const tmplPresRels = tmpl.getEntry("ppt/_rels/presentation.xml.rels");
  if (tmplPresRels) {
    const tmplXml = tmplPresRels.getData().toString("utf8");
    const lifted = [
      ...tmplXml.matchAll(
        /<Relationship[^/]*Target="(?:slideMasters|theme|notesMasters|handoutMasters)\/[^"]+"[^/]*\/>/g,
      ),
    ].map((m) => m[0]);
    // Reassign rId to avoid collisions with what's still in source rels.
    let nextId = 100;
    const renumbered = lifted.map((r) => r.replace(/Id="rId\d+"/, () => `Id="rId${nextId++}"`));
    presRels = presRels.replace(/<\/Relationships>/, renumbered.join("") + "</Relationships>");
  }
  out.deleteFile("ppt/_rels/presentation.xml.rels");
  out.addFile("ppt/_rels/presentation.xml.rels", Buffer.from(presRels, "utf8"));
}

// 6. Repoint each slide's rels at the template's first layout. pptxgenjs uses
//    absolute positions so the layout swap is a no-op for content placement.
const tmplLayouts = tmpl
  .getEntries()
  .filter((e) => /^ppt\/slideLayouts\/slideLayout\d+\.xml$/.test(e.entryName))
  .sort((a, b) => a.entryName.localeCompare(b.entryName));
const firstLayout = tmplLayouts[0]?.entryName.split("/").pop(); // e.g. "slideLayout1.xml"
if (firstLayout) {
  for (const entry of out.getEntries().slice()) {
    if (!/^ppt\/slides\/_rels\/slide\d+\.xml\.rels$/.test(entry.entryName)) continue;
    let xml = entry.getData().toString("utf8");
    xml = xml.replace(
      /(<Relationship[^/]*Target=")(?:\.\.\/slideLayouts\/)slideLayout\d+\.xml(")/g,
      `$1../slideLayouts/${firstLayout}$2`,
    );
    out.deleteFile(entry.entryName);
    out.addFile(entry.entryName, Buffer.from(xml, "utf8"));
  }
}

// 7. Rebuild [Content_Types].xml so PowerPoint can resolve everything.
//    Easiest: replace the source's <Override PartName="..."/> entries for the
//    replaced trees with the template's, plus carry over media types we added.
const ctEntry = out.getEntry("[Content_Types].xml");
if (ctEntry) {
  let ct = ctEntry.getData().toString("utf8");
  ct = ct.replace(
    /<Override[^/]*PartName="\/ppt\/(slideMasters|slideLayouts|theme|notesMasters|handoutMasters|fonts)\/[^"]+"[^/]*\/>/g,
    "",
  );
  // Lift the template's Override entries for the same trees.
  const tmplCt = tmpl.getEntry("[Content_Types].xml");
  if (tmplCt) {
    const tx = tmplCt.getData().toString("utf8");
    const lifted = [
      ...tx.matchAll(
        /<Override[^/]*PartName="\/ppt\/(?:slideMasters|slideLayouts|theme|notesMasters|handoutMasters|fonts)\/[^"]+"[^/]*\/>/g,
      ),
    ]
      .map((m) => m[0])
      .join("");
    ct = ct.replace(/<\/Types>/, lifted + "</Types>");
  }
  out.deleteFile("[Content_Types].xml");
  out.addFile("[Content_Types].xml", Buffer.from(ct, "utf8"));
}

await writeFile(outPath, out.toBuffer());
console.log("wrote", outPath, "(" + out.getEntries().length + " entries)");
